var documenterSearchIndex = {"docs":
[{"category":"section","location":"2D-preconditioner.html#Augmented-formulation","page":"Geometric preconditioner","text":"We consider the augmented formulation of the same problem as before\n\n    left beginarrayll\n    displaystyle min_xu x^0(t_f) 1em\n    textscdot x^0(t) = x_1(t)  tin t_0 t_fmathrmae 05em\n    phantommathrmsc dot x_1(t) = u(t)  tin t_0 t_fmathrmae 05em\n    phantommathrmsc u(t) in -11  tin t_0 t_f 05em\n    phantommathrmsc x(t_0) = x_0 quad x_1(t_f) = x_f\n    endarray right\n\nwith fixed x_0, t_0, x_f and t_f, and where x = (x^0 x_1). The augmented Hamiltonian of this problem is given by \n\n    H(xp) = p^0 x_1 + lvert p_1 rvert\n\nwhere p = (p^0 p_1) is the augmented costate, composed by the costate p_1 associated to the state x_1 and multiplier p^0 associated to the cost x^0 which is no longer fixed to -1. The flow varphi associated to the true Hamiltonian H is computed thanks to the textttflow and the textttHamiltonian functions.\n\nThe general shooting function S colon mathbb R^2 to mathbb R associated to this Hamiltonian is defined by \n\n    S(p_0) = pi_x big( varphi(t_0 x_0 p_0 t_f) big)\n\nwhere pi_x(x^0 x_1 p^0 x_1) = x_1 is still the state projection. \n\nWe are interested in two normalization of this shooting function, thanks to the homogeneity of the BC-extremals on the augmented costate, which are \n\n    S_1(p_0) = S(-1 p_0) qquad textand qquad S_2(p_0) = S big( eta(p) p_0 big)\n\nwhere the function eta colon -1 1 to mathbb R is defined by \n\n    eta(p) = -sqrt 1 - p^2\n\nThe following code creates and plots these shooting functions. \n\nusing OptimalControl\nusing Plots\nusing ForwardDiff\nusing DifferentialEquations\nusing MINPACK\nusing Statistics\n\nglobal α = 1\n\nfunction condition(z, t, integrator)                            # event when condition(z,t,integrator) == 0\n    x⁰,x,p⁰,p = z\n    return p\nend\n\nfunction affect!(integrator)                                    # action when condition == 0 \n    global α = -α\n    nothing\nend\n\ncb = ContinuousCallback(condition, affect!)                     # callback \nH(x, p) = p[1] * x[2] + α * p[2]\nϕ_ = Flow(OptimalControl.Hamiltonian(H), callback = cb)                        # flow with maximizing control \n\nfunction ϕ(t0, x0, p0, tf; kwargs...)  \n    if p0[2] == 0\n        global α = -sign(p0[1])\n    else\n        global α = sign(p0[2])\n    end\n    return ϕ_(t0, x0, p0, tf; kwargs...)\nend\n\nfunction ϕ((t0, tf), x0, p0; kwargs...)                         # flow for plot\n    if p0[2] == 0\n        global α = -sign(p0[1])\n    else\n        global α = sign(p0[2])\n    end\n    return ϕ_((t0, tf), x0, p0; kwargs...)\nend\n\nt0 = 0                                                          # initial time\nx0 = [0,0]                                                      # initial augmented state\ntf = 5                                                          # final time\nxT = 0                                                          # final state\n\nπ((x,p)) = x[2]                                                 # projection on state space\nη(p0) = -sqrt.(1 - p0.^2)                                       # function η(⋅)\n\nS(p0) = π( ϕ(t0, x0, p0, tf) ) - xT                             # general hooting function\n\nS₁(p0) = S([-1, p0])                                            # normalization 1\nS₂(p0) = abs(p0) < 1 ? S([η(p0), p0]) : sign(p0)*tf - xT        # normalization 2\n\n# Plot\nplt_S1 = plot(range(-7, 2, 500), S₁ , color = 2, label = \"\")\nplot!(xlabel = \"p₀\", ylabel = \"S₁\", xlim = [-7,2])\n\nplt_S2 = plot(range(-1, 1, 500), S₂, color = 3)\nplot!(xlabel = \"p₀\", ylabel = \"S₂\", xlim = [-1,1], legend=false)\n\nS_(p⁰, p) = S([p⁰, p])\nplt_S = surface(range(0, -1.5, 100), range(-8, 2, 100), S_, camera = (30,30))\nsurface!(xlabel = \"p⁰\", ylabel = \"p₀\", zlabel = \"φₓ\", xflip = true)\nplot3d!(-1*ones(100), range(-8, 2, 100), S₁.(range(-8, 2, 100)), label = \"S₁\")\nplot3d!(η.(range(-1, 1, 100)), range(-1, 1, 100), S₂.(range(-1, 1, 100)), label = \"S₂\")\n\nplt_S12 = plot(plt_S1, plt_S2, layout = (1,2))\nplt_total = plot(plt_S, plt_S12, layout = grid(2,1, heights = [2/3, 1/3]), size=(700, 600))\n\n@gif for i ∈ [range(30, 90, 50); 90*ones(25); range(90, 30, 50); 30*ones(25)]\n    plot!(plt_total[1], camera=(i,i), \n        zticks = i==90 ? false : true,\n        zlabel = i==90 ? \"\" : \"S\" )\nend\n\nAs done before, we use the solver texttthybrd1 from the textttMINPACKjl package to find a zero of S_2.\n\nglobal iterate_S2 = Vector{Float64}()                           # global vector to store iterates of the solver\n\nfunction S₂!(s₂, ξ)                                             # intermediate function\n    push!(iterate_S2, ξ[1])                                     # stock the iterate\n    return (s₂[:] .= S₂(ξ[1]); nothing)                     \nend\n\nJS₂(ξ) = ForwardDiff.jacobian(p0 -> [S₂(p0[1])], ξ)             # compute jacobian by forward differentiation\nJS₂!(js₂, ξ) = (js₂[:] .= JS₂(ξ); nothing)                      # intermediate function\n\nξ = [-0.5]                                                      # initial guess\np0_sol = fsolve(S₂!, JS₂!, ξ, show_trace = true)                # solve\nprintln(p0_sol)                                                 # print solution\n\nsol = ϕ((t0, tf), x0, [η(p0_sol.x[1]), p0_sol.x[1]], \n    saveat=range(t0, tf, 500))                                  # get optimal trajectory\n\n# plot\nt = sol.t\nx⁰ = [sol.u[i][1] for i in 1:length(sol.u)]\nx  = [sol.u[i][2] for i in 1:length(sol.u)]\np⁰ = [sol.u[i][3] for i in 1:length(sol.u)]\np  = [sol.u[i][4] for i in 1:length(sol.u)]\nu = sign.(p)\n\nplt_x⁰ = plot(t, x⁰, label = \"x⁰\")\nplt_x  = plot(t, x , label = \"x\" )\nplt_p⁰ = plot(t, p⁰, label = \"p⁰\", ylim=[-1,1])\nplt_p  = plot(t, p , label = \"p\" )\nplt_u  = plot(t, u,  label = \"u\" )\n\nplt_xp = plot(plt_x⁰, plt_p⁰, plt_x, plt_p, layout=(2, 2))\nplot(plt_xp, plt_u, layout = grid(2,1, heights = [2/3, 1/3]), size=(700, 600))","title":"Augmented formulation"},{"category":"section","location":"2D-preconditioner.html#Construction-of-the-geometric-preconditioner","page":"Geometric preconditioner","text":"The goal is now to use the geometric preconditioning method proposed in [mettre article]. For this purpose, the first step is to create some points in the boundary of the accessible augmented set, and to fit an ellipse on these points. \n\nThe second step is to create the linear diffeomorphism phi colon mathbb R^2 to mathbb R^2 (x^0x_1) to Ax + B that transforms the fitted ellipse into the unit circle, and that satisfy the condition \n\n    fracpartial phipartial x^0 = k e_1 \n\nwith k0 and e_1 = (10). In this context, we denote \n\n    A = left( beginarraycc k  A_x^0  0  A_x_1 endarray right)\n    qquad textand qquad \n    B = left( beginarrayc B_x^0  B_x_1 endarray right)\n\nThis diffeomorphism is given from the semi-axis ab 0, the angle theta in 0 fracpi2 between the semi-axis b and the x-axis, and the center c in mathbb R^2 by \n\n    phi(x) = r(-beta_0) s(a^-1 b^-1) r(theta) (x - c)\n\nwhere r and s correspond respectively to the rotation and the scale matrix, defined by \n\n    r(theta) = left( beginarraycc phantom - cos(theta)  sin(theta)  -sin(theta)  cos(theta) endarray right)\n    qquad textand qquad\n    s(ab) = left( beginarraycc a  0  0  b endarray right)\n\nand where beta_0 = arctan left(fraca sin(theta)b cos(theta) right). \n\n<article class=\"docstring\">\n<header>\n    <a class=\"docstring-article-toggle-button fa-solid fa-chevron-right\" href=\"javascript:;\" title=\"Expand docstring\"> </a>\n    <code>fit_ellipse</code> — <span class=\"docstring-category\">Function</span>\n</header>\n<section style=\"display: none;\"><div><pre><code class=\"language-julia hljs\">function fit_ellipse(x, y)\n    M = hcat(x.^2, x.*y, y.^2, x, y)                            # quadratic form of ellipse\n    p = M\\ones(length(x))                                       # fit parameters for the ellipse\n    A, B, C, D, E = p\n    F = -1.0\n    # calculate the parameters from quadratic\n    Δ = B^2 - 4*A*C\n    Λ = (A-C)^2 + B^2\n    b, a = [-sqrt(clamp( 2*(A*E^2 + C*D^2 - B*D*E + Δ*F)*\n            ( (A+C) + op(sqrt(Λ)) ), 0, Inf)) / Δ   for op in (+, -)]\n    θ = atan(-B, C-A)/2\n    c = [(2*C*D - B*E)/Δ, (2*A*E - B*D)/Δ]\n    return a, b, -θ+Base.π/2, c\nend</code><button class=\"copy-button fa-solid fa-copy\" aria-label=\"Copy this code ;opblock\" title=\"Copy\"></button></pre></div>\n</section>\n</article>\n\nfunction fit_ellipse(x, y) # hide\n    M = hcat(x.^2, x.*y, y.^2, x, y) # hide\n    p = M\\ones(length(x)) # hide\n    A, B, C, D, E = p # hide\n    F = -1.0 # hide\n    Δ = B^2 - 4*A*C # hide\n    Λ = (A-C)^2 + B^2 # hide\n    b, a = [-sqrt(clamp( 2*(A*E^2 + C*D^2 - B*D*E + Δ*F) * ( (A+C) + op(sqrt(Λ)) ), 0, Inf)) / Δ   for op in (+, -)] # hide\n    θ = atan(-B, C-A)/2 # hide\n    c = [(2*C*D - B*E)/Δ, (2*A*E - B*D)/Δ] # hide\n    return a, b, -θ+Base.π/2, c # hide\nend # hide\nnothing # hide\n\nn = 15                                                          # number of points for fit : 2n\nn_ = 100                                                        # number of points for plot: 2n_\np0 = [[[-1, i] for i ∈ range(-tf, 0, n)];                       # initial costate for fit\n      [[1, i] for i ∈ range(tf, 0, n)]]     \np0_ = [[[-1, i] for i ∈ range(-tf, 0, n_)];                     # initial costate for plot\n       [[1, i] for i ∈ range(tf, 0, n_)]]\n\nx = zeros(2, 2*n); p = zeros(2,2*n)                             # init final state and costate\nx_ = zeros(2, 2*n_); p_ = zeros(2, 2*n_)\nfor i = 1:length(p0)\n    x[:,i], p[:,i] = ϕ(t0, x0, p0[i], tf)                       # compute flow for fit\nend\nfor i = 1:length(p0_)\n    x_[:,i], p_[:,i] = ϕ(t0, x0, p0_[i], tf)                    # compute flow for plot\nend\n\na, b, θ, c = fit_ellipse(x[1,:], x[2,:])                        # fit ellipse\nr(β) = [[cos(β), sin(β)] [-sin(β), cos(β)]]                     # 2x2 rotation matrix\ns(a,b) = [[a,0] [0,b]]                                          # 2x2 scale matrix\nβ = range(-Base.π, Base.π; length = 100)                        # angle for plot ellipse\nxₑ = r(-θ)*s(a,b)*\n    transpose(reduce(hcat,[sin.(β), cos.(β)])).+c               # points of the ellipse\n\n# construction of the linear diffeomorphism φ(x) = Ax + B\nd = (a*sin(θ))/(b*cos(θ)); β₀ = atan(d)                         # intermediate values\nA = r(-β₀)*s(1/a,1/b)*r(θ); B = -A*c                            # calculate A and B\nφ(x) = A*x .+ B                                                 # function φ\n\ny = φ(x); y_ = φ(x_); yₑ = φ(xₑ)                                # compute φ on x, x_ and xₑ\n\n# plot\nplt_x = plot(x_[2,:], x_[1,:], label = \"\")\nscatter!(x[2,:], x[1,:], label=\"Observations\", legend = :topleft)\nplot!(xₑ[2,:], xₑ[1,:], label = \"Fitted ellipse\")\nplot!(xlim = [-15,15], ylim = [-15,15], xlabel = \"x\", ylabel = \"x⁰\")\n\nplt_y = plot(y_[2,:], y_[1,:], label = \"\")\nscatter!(y[2,:], y[1,:], label=\"\")\nplot!(yₑ[2,:], yₑ[1,:], label = \"\")\nplot!( xlabel = \"y\", ylabel = \"y⁰\")\n\nplot(plt_x, plt_y, layout = (1,2), size=(800, 400))\n\nThe general shooting function T colon mathbb R^2 to mathbb R in the new coordinate is defined by \n\n    T(q) = A_x_1 varphi big(t_0 x_0 p_0(A^top q) t_f) + B_x_1 - y_T\n\nwhere the function p_0 colon mathbb R^2 to mathbb R^2 correspond to the mapping between the final and the initial augmented costate, and is given by\n\n    p_0(p^0 p_1) = (p^0 p_1 + p^0 t_f)\n\nand y_T = A_x_1 x_T + B_x to the target in the new system of coordinates. By using the definition of S and y_T, we obtain \n\nbeginalign*\n    T(q) = A_x_1 varphi big(t_0 x_0 p_0(A^top q) t_f) + B_x_1 - (A_x_1 x_T + B_x_1) \n    = A_x_1 (S circ p_0)(A^top q)\nendalign*\n\nwhich highlight that the proposed geometric preconditioning method is a left and right side preconditioner of the shooting function. Finally, we define the two shooting functions T_1 and T_2 by using the two method of normalization used before for the function S \n\n    T_1(p) = T(-1 p) qquad textand qquad T_2(p) = T big(eta(p) p big)\n\np₀(p) = [p[1], p[2] + p[1]*tf]                                  # function p₀(⋅)\nAₓ = A[2,2]; Bₓ = B[2]                                          # Aₓ and Bₓ\nyT = Aₓ*xT + Bₓ                                                 # target in the new coordinate \nT(q) = Aₓ*(S ∘ p₀)(transpose(A)*q)                              # state flow in the new coordinates\nT₁(q) = T([-1, q])                                              # normalization 1\nT₂(q) = abs(q) < 1 ? T([η(q), q]) : sign(q)*(Aₓ*tf + Bₓ)        # normalization 2\n\n# Plot\nplt_S1 = plot(range(-3, 3, 500), T₁ , color = 2)\nplot!([-3,3], [yT,yT], color = :black)\nplot!(xlabel = \"q₀\", ylabel = \"T₁\", xlim = [-3,3], legend=false)\n\nplt_S2 = plot(range(-1, 1, 500), T₂, color = 3)\nplot!([-1,1], [yT,yT], color = :black)\nplot!(xlabel = \"q₀\", ylabel = \"T₂\", xlim = [-1,1], legend=false)\n\nT_(q⁰, q) = T([q⁰, q])\nplt_S = surface(range(0, -1.5, 100), range(-3, 3, 100), T_, camera = (30,30))\nsurface!(xlabel = \"q⁰\", ylabel = \"q₀\", zlabel = \"T\", xflip = true)\nplot3d!(-1*ones(100), range(-3, 3, 100), T₁.(range(-3, 3, 100)), label = \"T₁\")\nplot3d!(η.(range(-1, 1, 100)), range(-1, 1, 100), T₂.(range(-1, 1, 100)), label = \"T₂\")\n\nplt_S12 = plot(plt_S1, plt_S2, layout = (1,2))\nplt_total = plot(plt_S, plt_S12, layout = grid(2,1, heights = [2/3, 1/3]), size=(700, 600))\n\n@gif for i ∈ [range(30, 90, 50); 90*ones(25); range(90, 30, 50); 30*ones(25)]\n    plot!(plt_total[1], camera=(i,i), \n        zticks = i==90 ? false : true,\n        zlabel = i==90 ? \"\" : \"T\" )\nend","title":"Construction of the geometric preconditioner"},{"category":"section","location":"2D-preconditioner.html#Preconditioned-shoot","page":"Geometric preconditioner","text":"global iterate_T2 = Vector{Float64}()                           # global vector to store iterates of the solver\n\nfunction T₂!(t₂, ξ)                                             # intermediate function\n     push!(iterate_T2, ξ[1])  \n     return (t₂[:] .= T₂(ξ[1]); nothing)                   \nend\n\nJT₂(ξ) = ForwardDiff.jacobian(q0 -> [T₂(q0[1])], ξ)             # compute jacobian by forward differentiation\nJT₂!(jt₂, ξ) = (jt₂[:] .= JT₂(ξ); nothing)                      # intermediate function\n\nξ = [0.5]                                                       # initial guess\nq_sol = fsolve(T₂!, JT₂!, ξ, show_trace = true)                 # solve\nprintln(q_sol)                                                  # print solution\n\np0_sol = p₀(transpose(A)*[η(q_sol.x[1]), q_sol.x[1]])           # get the optimal initial costate in old coordinates\nsol = ϕ((t0, tf), x0, p0_sol, saveat=range(t0, tf, 500))        # get optimal trajectory\n\n# plot\nt = sol.t\nx⁰ = [sol.u[i][1] for i in 1:length(sol.u)]\nx  = [sol.u[i][2] for i in 1:length(sol.u)]\np⁰ = [sol.u[i][3] for i in 1:length(sol.u)]\np  = [sol.u[i][4] for i in 1:length(sol.u)]\nu = sign.(p)\n\nplt_x⁰ = plot(t, x⁰, label = \"x⁰\")\nplt_x  = plot(t, x , label = \"x\" )\nplt_p⁰ = plot(t, p⁰, label = \"p⁰\", ylim=[-1,1])\nplt_p  = plot(t, p , label = \"p\" )\nplt_u  = plot(t, u,  label = \"u\" )\n\nplt_xp = plot(plt_x⁰, plt_p⁰, plt_x, plt_p, layout=(2, 2))\nplot(plt_xp, plt_u, layout = grid(2,1, heights = [2/3, 1/3]), size=(700, 600))","title":"Preconditioned shoot"},{"category":"section","location":"2D-preconditioner.html#Comparison","page":"Geometric preconditioner","text":"It is shown in [mettre article] that if the boundary of augmented accessible set is the fitted ellipse then the shooting function T_2 is the identity function. Due to the error of the approximation, the function T_2 is not the identity, but we hope that this function is close to this ideal function, and so that the convergence of T_2 is faster than the one of S_2. \n\nThe following code compares the convergence of these two shooting function. We also study for these functions the domain of initial guesses for the solver that hit the bounds -1 1 during the solving process. \n\n## initial guesses\nN = 1000; ξ = range(-1.,1.,N)                               \n\n# initialization of the matrix\nfnorms_S2 = zeros(N, 100); fnorms_T2 = zeros(N, 100)        \nfnorms_T2_in_x = zeros(N, 100)\niterates_S2 = zeros(N, 100); iterates_T2 = zeros(N, 100)\nconv_S2 = zeros(N,1); conv_T2 = zeros(N,1)                  \n#-1 : not converged; 1 converged; 0: converged but hit bounds\n\n# intermediate function to get value of S from T iterates\nT₂_(q0) = abs(q0) < 1 ? S(p₀(transpose(A)*[η.(q0),q0])) : sign(q0) * tf - xT\n\nfor i = 1:N\n    # remove old iterates\n    global iterate_S2 = Vector{Float64}()\n    global iterate_T2 = Vector{Float64}()\n\n    # solve \n    q_sol_S2 = fsolve(S₂!, JS₂!, [ξ[i]], show_trace = false, tracing = true)\n    q_sol_T2 = fsolve(T₂!, JT₂!, [ξ[i]], show_trace = false, tracing = true)\n\n    # store results is converged \n    if q_sol_S2.converged\n        fnorm_S2 = [q_sol_S2.trace.trace[j].fnorm for j ∈ 1:length(q_sol_S2.trace.trace)]\n        iterates_S2[i,1:length(iterate_S2)] = iterate_S2\n        conv_S2[i] = length(findall(x-> abs(x) > 1, iterate_S2)) == 0\n        fnorms_S2[i,1:length(fnorm_S2)] = fnorm_S2\n    else\n        conv_S2[i] = -1\n    end\n    if q_sol_T2.converged\n        fnorm_T2 = [q_sol_T2.trace.trace[j].fnorm for j ∈ 1:length(q_sol_T2.trace.trace)]\n        iterates_T2[i,1:length(iterate_T2)] = iterate_T2\n        conv_T2[i] = length(findall(x-> abs(x) > 1, iterate_T2)) == 0\n        fnorms_T2[i,1:length(fnorm_T2)] = fnorm_T2 \n        fnorms_T2_in_x[i, 1:length(iterate_T2)] = abs.(T₂_.(iterate_T2))\n    else\n        conv_T2[i] = -1\n    end\nend\n\n# mean \nmean_fnorms_S2 = mean(fnorms_S2, dims = 1)\nmean_fnorms_T2 = mean(fnorms_T2, dims = 1)\nmean_fnorms_T2_in_x = mean(fnorms_T2_in_x, dims = 1)\n\n# remove zeros with tolerance ε \nε = 1e-9;\nmean_fnorms_S2 = mean_fnorms_S2[1:findall(x -> x < ε, mean_fnorms_S2)[1][2]]\nmean_fnorms_T2 = mean_fnorms_T2[1:findall(x -> x < ε, mean_fnorms_T2)[1][2]]\nmean_fnorms_T2_in_x = mean_fnorms_T2_in_x[1:findall(x -> x < ε, mean_fnorms_T2_in_x)[1][2]]\n\n# plots\nplt_1 = plot(0:length(mean_fnorms_S2)-1, mean_fnorms_S2, label = \"S₂\")\nplot!(0:length(mean_fnorms_T2)-1, mean_fnorms_T2, label = \"T₂\")\nplot!(0:length(mean_fnorms_T2_in_x)-1, mean_fnorms_T2_in_x, label = \"T₂ in x\")\nplot!(yaxis = :log10, xlim = [0, 30], ylim = [ε, 10], xlabel = \"Error\", ylabel = \"Iterations\")\n\nplt_21 = plot(ξ, S₂, color = :black, label = \"\")\ncolor = [conv_S2[i]==1 ? :green : conv_S2[i] == 0 ? :blue : :red for i ∈ 1:N]\nscatter!(ξ, S₂, color = color, markerstrokecolor = color, marker = 2, label =\"\")\nplot!([-1,1], [xT,xT], color = :black, label = \"\")\nplot!(xlabel = \"p₀\", ylabel = \"S₂\", label = \"\")\n\nplt_22 = plot(ξ, T₂, color = :black, label = \"\")\ncolor = [conv_T2[i]==1 ? :green : conv_T2[i] == 0 ? :blue : :red for i ∈ 1:N]\nscatter!(ξ, T₂, markercolor = color, markerstrokecolor = color, marker = 2, label = \"\")\nplot!([-1,1], [yT,yT], color = :black, label = \"\")\nplot!(xlabel = \"q₀\", ylabel = \"T₂\", label = \"\")\nscatter!(1,1, markercolor = :green, markerstrokecolor = :green, marker = 2, label = \"converged\")\nscatter!(1,1, markercolor = :blue, markerstrokecolor = :blue, marker = 2, label = \"converged but hit bounds\")\nscatter!(1,1, markercolor = :red, markerstrokecolor = :red, marker = 2, label = \"not converged\")\n\nplt_2 = plot(plt_21, plt_22, layout = (1,2))\nplot(plt_1, plt_2, layout = grid(2,1, heights = [0.5, 0.5]), size=(700, 600))","title":"Comparison"},{"category":"section","location":"index.html#Optimal-control-problem","page":"Introduction","text":"We consider the following optimal control problem \n\n    left beginarrayll\n    displaystyle min_xu int_t_0^t_f x(t) mathrm dt 1em\n    textscdot x(t) = u(t)  tin t_0 t_fmathrmae 05em\n    phantommathrmsc u(t) in -11  tin t_0 t_f 05em\n    phantommathrmsc x(t_0) = x_0 quad x(t_f) = x_f\n    endarray right\n\nwith x_0, t_0, x_f and t_f fixed. This problem is simple, and can be analytically solve without the use of numerical method. However, the goal is to solve this problem by indirect shooting.  ","title":"Optimal control problem"},{"category":"section","location":"index.html#Reproducibility","page":"Introduction","text":"_downloads_toml(\".\") # hide\n\n<details style=\"margin-bottom: 0.5em; margin-top: 1em;\"><summary>ℹ️ Version info</summary>\n\nversioninfo() # hide\n\n</details>\n\n<details style=\"margin-bottom: 0.5em;\"><summary>📦 Package status</summary>\n\nPkg.status() # hide\n\n</details>\n\n<details style=\"margin-bottom: 0.5em;\"><summary>📚 Complete manifest</summary>\n\nPkg.status(; mode = PKGMODE_MANIFEST) # hide\n\n</details>","title":"Reproducibility"},{"category":"section","location":"2D-example.html#Indirect-method","page":"Indirect shooting","text":"The goal is to solve this toy problem using the indirect method. a particular attention is given on the computation of the jacobian of the well-known shooting function, which is not straightforward due to the non-differentiability of the flow with respect to the initial costate.\n\nLet's start by import the package\n\nusing OptimalControl                            # for optimal control\nusing Plots                                     # for plotting\nusing ForwardDiff                               # for automatic differentiation\nusing DifferentialEquations                     # for solving differential equations\nusing MINPACK                                   # for solving nonlinear systems\n\nand define the studied optimal control problem \n\nt0 = 0; x0 = 0; tf = 5; xf = 0                  # Initial and final time and state\n\n# Problem definition\n@def ocp begin                          \n\n    t ∈ [ t0, tf ], time\n    x ∈ R, state\n    u ∈ R, control\n\n    x(t0) == x0\n    x(tf) == xf\n\n    ẋ(t) == u(t)      \n\n    ∫( x(t) ) → min\n\nend","title":"Indirect method"},{"category":"section","location":"2D-example.html#Indirect-method-2","page":"Indirect shooting","text":"The pseudo-Hamiltonian associated to the studied optimal control problem is defined by\n\n    h(xpp^0u) = p^0 x + p u\n\nFor the sake of simplicity, we assume that the BC-extremals associated to the solution of the studied problem is normal, and so we fix p^0 = -1. According to the Pontryagin maximum principle, the maximizing control is given by u(xp) to mathrmsign(p). This function is non-differentiable, and may lead to numerical issues.  \n\nLet's start by defining the problem. \n\nThanks to the control-toolbox, the flow varphi of the (true) Hamiltonian\n\n    H(xp) = h(xp-1 u(xp)) = p^0 x + lvert p rvert \n\nis given by the function Flow. The shooting function S colon mathbbR to mathbbR is defined by\n\n    S(p_0) = pi big( varphi(t_0 x_0 p_0 t_f) big) - x_f\n\nwhere pi (xp) = x is the classical x-space projection. The shooting function S is plotted below.\n\nϕ = Flow(ocp, (x,p) -> sign(p))                 # Flow with maximizing control \nπ((x,p)) = x;                                   # Projection on state space\n\nS(p0) = π( ϕ(t0, x0, p0, tf) ) - xf;            # Shooting function\nnle = p0 -> [S(p0[1])]                          # Intermediate function\n\n# Plot\nplt = plot(xlim = (-7, 2), ylim = (-6, 6), size=(800, 500))\nplot!(plt, S, label = \"S\")\nplot!(plt, [-7,2], [0,0], c = :black, ls = :dash, label = nothing)","title":"Indirect method"},{"category":"section","location":"2D-example.html#Finite-difference-method","page":"Indirect shooting","text":"The main goal now is to find the zero of S. To this purpose, we use the numerical solver hybrd1 given in the package MINPACK.jl. If we don't provide the Jacobian J_S of S to the solver, the finite difference method is used to approximate it. \n\nξ = [-1.0]                                              # Initial guess\nS!(s, ξ) = (s[:] .= S(ξ[1]); nothing)                   # Intermediate function\np0_sol = fsolve(S!, ξ, show_trace = true)               # Solve\n\nsol = ϕ((t0, tf), x0, p0_sol.x)                         # Get the optimal trajectory\nplot(sol, size = (800,600))                             # Plot","title":"Finite difference method"},{"category":"section","location":"2D-example.html#Automatic-differentiation-(wrong-way)","page":"Indirect shooting","text":"Now, we want to provide J_S to the solver, thanks to the ForwardDiff.jl package. This Jacobian is computed with the variational equation, and leads to a false result in our case. The reason of this issue is explained below.\n\ndetails: Details\nDenoting z = (xp), we have     varphi(t_0 z_0 t_f) = z_0 + int_t_0^t_f vec Hbig(varphi(t_0 z_0 t)big) mathrm dt If we assume that z_0 to varphi(t_0 z_0 t_f) is differentiable, we have      fracpartial varphipartial z_0(t_0 z_0 t_f)cdot delta z_0 =  delta z_0 + int_t_0^t_f vec Hbig(varphi(t_0 z_0 t)big)cdot left( fracpartial varphipartial z_0(t_0 z_0 t) cdot delta z_0 right) mathrm dt and so, z_0 to fracpartial varphipartial z_0(t_0 z_0 t_f)cdot delta z_0 is solution of the variational equations    fracpartial delta zpartial t(t) = vec Hbig(varphi(t_0 z_0 t_f)big) cdot delta z(t) qquad delta z(t_0) = delta z_0In the studied optimal control problem, we have     vec H(xp) = (mathrmsign(p) -1) and so, we have vec H(z) = 0_2 almost everywhere, which implies    fracpartial varphipartial z_0(t_0 z_0 t_f) cdot delta z_0 = mathrmexpbig((t_f-t_0) 0_2 big)cdot delta z_0 = delta z_0The Jacobian of the shooting function is then given by     S(p_0) = pi left( fracpartial varphipartial p_0(t_0 x_0 p_0 t_f) right) = pi left( fracpartial varphipartial z_0(t_0 z_0 t_f) cdot (01) right) = pi(01) = 0 \n\nξ = [-1.0]                                          # Initial guess\nJS(ξ) = ForwardDiff.jacobian(p -> [S(p[1])], ξ)     # Compute jacobian by forward differentiation\nprintln(\"ξ = \", ξ[1])\nprintln(\"JS(ξ) : \", JS(ξ)[1])\n\nHowever, the solver \\texttt{hybrd1} uses rank 1 approximations to actualize the Jacobian instead of compute it at each iteration, which imply that it still converges to the solution even if the given Jacobian is completely false.\n\nJS!(js, ξ) = (js[:] .= JS(ξ); nothing)              # Intermediate function\np0_sol = fsolve(S!, JS!, ξ, show_trace = true)      # Solve\n\nsol = ϕ((t0, tf), x0, p0_sol.x)                     # Get the optimal trajectory\nplt = plot(sol, size = (800, 600))                  # Plot","title":"Automatic differentiation (wrong way)"},{"category":"section","location":"2D-example.html#Automatic-differentiation-(good-way)","page":"Indirect shooting","text":"The goal is to provide the true Jacobian of S by using the \\texttt{ForwardDiff} package, and so we need to indicate to the solver that the dynamic of the system change when p = 0.\n\nTo understand why we need to give this information to the solver, see the following details. \n\ndetails: Details\nThe problem is that the Hamiltonian H is not differentiable everywhere due to the maximizing control. This control is bang-bang (u = 1 and u = -1).  Let now construct the two smooth Hamiltonians associated to these two controls     H^+(xp) = h(xp-11) = -x + p qquad textand qquad H^-(xp) = h(xp-1-1) =  -x - p Their associated vector fields are given by     vec H^+(xp) = (11) qquad textand qquad vec H^-(xp) = (-1 1) and their associated flow correspond to     varphi^+(t_0 z_0 t_f) = z_0 + left( beginarrayc 1  1 endarray right) (t_f -t_0)\n    qquad textand qquad \n    varphi^-(t_0 z_0 t_f) = z_0 + left( beginarrayc -1  phantom- 1 endarray right) (t_f -t_0)If we assume that the optimal structure of the problem is negative then positive bangs, then the associated flow is defined by      varphi(t_0 z_0 t_f) = varphi^+ big( t_1(z_0) varphi^-big(t_0 z_0 t_1(z_0)big) t_f big)with the following condition     pi_p big( varphi^-(t_0 z_0 t_1(z_0)) big) = 0where pi_p(xp) = p is the classical p-space projection. By devlopping this last condition, an explicit form of the function t_1(cdot) is given by     t_1(x_0 p_0) = t_0 - p_0Finally, we have     beginalign*\n    fracpartial varphipartial z_0 \n    = fracpartial varphi^+partial t_0 fracpartial t_1partial z_0 + fracvarphi^+partial z_0 left( fracpartial varphi^-partial z_0 + fracpartial varphi^-partial t_f fracpartial t_1partial z_0 right) \n    = left( beginarrayc -1  -1 endarray right) left( beginarraycc0  -1 endarray right) + left( beginarraycc 1  0  0  1 endarray right) left\n    left( beginarraycc 1  0  0  1 endarray right) + left( beginarrayc -1  phantom - 1 endarray right) left( beginarraycc0  -1 endarray right)\n    right \n    = left( beginarraycc 0  1  0  1 endarray right) + left( beginarraycc 1  0  0  1 endarray right) + left( beginarraycc 0  phantom -1  0  -1 endarray right)  \n    = left( beginarraycc 1  2  0  1 endarray right)\n    endalign*and so, we have that     S(p_0) = pi left( fracpartial varphipartial p_0(t_0 x_0 p_0 t_f) right) = pi left( fracpartial varphipartial z_0(t_0 z_0 t_f) cdot (01) right) = pi(21) = 2\n\nTo provide this change of dynamic to the solver, we need to use a callback during the integration that will execute the function affect! when condition is equals to zero.\n\nFor us, the condition is given by (xp) to p. For the affect! function, we use a global parameter alpha. This parameter will be set to pm 1 at the beginning of the integration and it sign will change with the affect! function. \n\nThanks to the control.jl package, the created callback can be easily pass to the integrator through the Flow function. This in done in the following collapsed block.\n\ndetail: Detail\n# Parameter: ̇p(t) = α with α = ±1\nglobal α\n\n# Event when condition(x,p) == 0\nfunction condition(z, t, integrator)                        \n    x,p = z\n    return p\nend\n\n# Action when condition == 0 \nfunction affect!(integrator)\n    global α = -α\n    nothing\nend\n\ncb = ContinuousCallback(condition, affect!)                 # Callback \nφ_ = Flow(ocp, (x,p) -> α, callback = cb)                   # Intermediate flow\n\n# Flow for the solver\nfunction φ(t0, x0, p0, tf; kwargs...)                       \n    global α = sign(p0)\n    return φ_(t0, x0, p0, tf; kwargs...)\nend\n\n# Flow for plot\nfunction φ((t0, tf), x0, p0; kwargs...)                     \n    global α = sign(p0)\n    return φ_((t0, tf), x0, p0; kwargs...)\nend\n\n# Plot solution\nfunction plot_sol(sol; size = (800, 600))\n    \n    t = sol.time_grid.value\n    x = state(sol)\n    p = costate(sol)\n    u = sign ∘ p\n\n    plt_x = plot(t, x, label = nothing, ylabel = \"x\", title = \"state\", titlefontsize = 10, lw = 2)\n    plt_p = plot(t, p, label = nothing, title = \"costate\", titlefontsize = 10, lw = 2)\n    plt_u = plot(t, u, label = nothing, ylabel = \"u\", title = \"control\", titlefontsize = 10, lw = 2)\n\n    plt_xp = plot(plt_x, plt_p, layout=(1, 2))\n    return plot(plt_xp, plt_u, layout = (2, 1), size = size)\nend\n\nnothing; # hide\n\nShoot(p0) = π( φ(t0, x0, p0, tf) ) - xf                         # Shooting function\nξ = [-1.0]                                                      # Initial guess\nJShoot(ξ) = ForwardDiff.jacobian(p -> [Shoot(p[1])], ξ)         # Compute jacobian by forward differentiation\nprintln(\"ξ = \", ξ[1])\nprintln(\"JS(ξ) : \", JShoot(ξ)[1])\n\nShoot!(shoot, ξ) = (shoot[:] .= Shoot(ξ[1]); nothing)           # Intermediate function\nJShoot!(jshoot, ξ) = (jshoot[:] .= JShoot(ξ); nothing)          # Intermediate function\np0_sol = fsolve(Shoot!, JShoot!, ξ, show_trace = true)          # Solve\n\nsol = φ((t0, tf), x0, p0_sol.x[1], saveat=range(t0, tf, 500))   # Get optimal trajectory\nplot_sol(sol)","title":"Automatic differentiation (good way)"}]
}
